content.content:
380	      }
381	    }
382	  };
383	  inst.client.on("update", updateHandler);
384	
385	  try {
386	    // Multi-turn loop: keep prompting until agent says done or budget exhausted
387	    let turns = 0;
388	    let lastStopReason = "";
389	
390	    const deadline = Date.now() + timeoutMs;
391	
392	    while (turns < maxTurns && Date.now() < deadline) {
393	      turns++;
394	      updateTask(delegate.id, { turns, lastOutput: output.slice(-200) || undefined });
395	      broadcastSSE(delegate.id, { type: "status", status: "running", turns });
396	      const promptText = turns === 1 ? prompt : "[系統] 繼續執行，完成後在回覆中說明結果。";
397	
398	      const result = await Promise.race([
399	        inst.client.prompt(promptText),
400	        new Promise<never>((_, reject) =>
401	          setTimeout(() => reject(new Error("timeout")), Math.max(1000, deadline - Date.now())),
402	        ),
403	      ]);
404	
405	      lastStopReason = result.stopReason;
406	      // If agent stopped normally (end_turn), check if it needs more turns
407	      if (lastStopReason === "end_turn" || lastStopReason === "stop") break;
408	      // tool_use means agent is still working — loop for next turn
409	    }
410	
411	    // Extract summary from output (last 2000 chars as summary)
412	    const summary = output.length > 2000 ? output.slice(-2000) : output || "(no output)";
413	
414	    const status: ResultPayload["status"] =
415	      Date.now() >= deadline ? "timeout" : "done";
416	
417	    completeTask(delegate.id, status, { lastOutput: summary.slice(0, 200) });
418	    broadcastSSE(delegate.id, { type: "status", status });
419	
420	    // Persist transcript for /memorytoskill
421	    appendTranscript(target, "user", prompt).catch(() => {});
422	    appendTranscript(target, "assistant", output).catch(() => {});
423	
424	    logEvent("specialist_done", { target, taskId: delegate.id, status, turns });
425	    return {
426	      payload: { id: delegate.id, status, summary },
427	      rawOutput: output,
428	    };
429	  } catch (err: any) {
430	    const msg = err.message ?? String(err);
431	    const failStatus = msg.includes("timeout") ? "timeout" : "failed";
432	    completeTask(delegate.id, failStatus, { error: msg.slice(0, 200) });
433	    broadcastSSE(delegate.id, { type: "status", status: failStatus });
434	    logEvent("specialist_done", { target, taskId: delegate.id, status: failStatus, error: msg.slice(0, 100) });
435	    return {
436	      payload: { id: delegate.id, status: "failed", summary: `Error: ${msg.slice(0, 500)}` },
437	      rawOutput: output,
438	    };
439	  } finally {
440	    inst.client.removeListener("update", updateHandler);
441	    inst.busy = false;
442	    closeInstance(target);
443	  }
444	}
