446	function buildGoalPrompt(d: DelegatePayload, preamble: string, enrichment?: string): string {
447	  let prompt = preamble;
448	  if (enrichment) prompt += enrichment;
449	  prompt += `[Delegation Task — id: ${d.id}]\n`;
450	  prompt += `Goal: ${d.goal}\n`;
451	  if (d.context) prompt += `Context: ${d.context}\n`;
452	  prompt += `\nComplete this task. When done, summarize what you accomplished.`;
453	  return prompt;
454	}
