472	/**
473	 * Dispatch multiple delegations in parallel. Each gets its own fresh instance.
474	 * Returns after all settle (Promise.allSettled).
475	 */
476	export async function dispatchParallel(
477	  tasks: ParallelTask[],
478	  userId?: number,
479	): Promise<ParallelResult[]> {
480	  const promises = tasks.map(async (task): Promise<ParallelResult> => {
481	    const entry = getEntry(task.target);
482	    if (!entry) {
483	      return { taskId: task.taskId, target: task.target, status: "failed", summary: `Unknown specialist: ${task.target}`, rawOutput: "" };
484	    }
485	
486	    let instanceId = "";
487	    try {
488	      registerTask({
489	        taskId: task.taskId,
490	        type: "parallel_delegate",
491	        specialist: task.target,
492	        goal: task.payload.goal.slice(0, 100),
493	      });
494	      const spawned = await spawnNew(task.target, userId);
495	      instanceId = spawned.instanceId;
496	      const inst = spawned.inst;
497	
498	      const maxTurns = task.payload.maxTurns ?? entry.maxTurns ?? 15;
499	      const timeoutMs = entry.timeoutMs ?? 1_800_000;
500	
501	      const preamble = await buildSpecialistPreamble(task.target, userId ?? 0).catch(() => "");
502	      const scope = await getSpecialistScope(task.target).catch(() => undefined);
503	      const enrichment = await runEnrichment(task.payload.goal, userId ?? 0, undefined, scope).catch(() => "");
504	      const prompt = buildGoalPrompt(task.payload, preamble, enrichment);
505	
506	      let output = "";
507	      const updateHandler = (u: SessionUpdate) => {
508	        const up = u.update;
509	        if (
510	          (up.sessionUpdate === "agent_message_chunk" || up.sessionUpdate === "agent_thought_chunk")
511	        ) {
512	          const content = up.content as { type?: string; text?: string } | undefined;
513	          if (content?.type === "text" && typeof content.text === "string") {
514	            output += content.text;
515	            const role = up.sessionUpdate === "agent_thought_chunk" ? "thought" : "agent";
516	            broadcastSSE(task.taskId, { type: "chunk", role, text: content.text });
517	          }
518	        }
519	      };
520	      inst.client.on("update", updateHandler);
521	
522	      try {
523	        let turns = 0;
524	        const deadline = Date.now() + timeoutMs;
525	
526	        while (turns < maxTurns && Date.now() < deadline) {
527	          turns++;
528	          const promptText = turns === 1 ? prompt : "[系統] 繼續執行，完成後在回覆中說明結果。";
529	          const result = await Promise.race([
530	            inst.client.prompt(promptText),
531	            new Promise<never>((_, reject) =>
532	              setTimeout(() => reject(new Error("timeout")), Math.max(1000, deadline - Date.now())),
533	            ),
534	          ]);
535	          if (result.stopReason === "end_turn" || result.stopReason === "stop") break;
536	        }
537	
538	        const summary = output.length > 2000 ? output.slice(-2000) : output || "(no output)";
539	        const status: ParallelResult["status"] = Date.now() >= deadline ? "timeout" : "done";
540	
541	        // Verifier gate (same as RELAY_DELEGATE path)
542	        if (status === "done" && output.length > 50) {
543	          const vr = await verifySpecialistOutput(task.payload.goal, output);
544	          logEvent("specialist_done", { taskId: task.taskId, target: task.target, verifier: vr.pass ? "PASS" : "NEEDS_FIX", source: vr.source, issues: vr.issues?.slice(0, 300) });
545	          if (!vr.pass && vr.issues) {
546	            console.log(`[parallel:${task.taskId}] verifier NEEDS_FIX (${vr.source}): ${vr.issues.slice(0, 100)}`);
547	            // Retry once
548	            try {
549	              const retryPrompt = buildRetryPrompt(task.payload.goal, vr.issues);
550	              output = "";
551	              const retryResult = await Promise.race([
552	                inst.client.prompt(retryPrompt),
553	                new Promise<never>((_, reject) => setTimeout(() => reject(new Error("timeout")), 120_000)),
554	              ]);
555	              void retryResult;
556	            } catch { /* retry failed — use original output */ }
557	          }
558	        }
559	
560	        completeTask(task.taskId, status, { lastOutput: summary.slice(0, 200) });
561	
562	        appendTranscript(task.target, "user", prompt).catch(() => {});
563	        appendTranscript(task.target, "assistant", output).catch(() => {});
564	
565	        return { taskId: task.taskId, target: task.target, status, summary, rawOutput: output };
566	      } finally {
567	        inst.client.removeListener("update", updateHandler);
568	        closeParallelInstance(instanceId);
569	      }
570	    } catch (err: any) {
571	      if (instanceId) closeParallelInstance(instanceId);
572	      const msg = (err.message ?? String(err)).slice(0, 500);
573	      completeTask(task.taskId, "failed", { error: msg.slice(0, 200) });
574	      return { taskId: task.taskId, target: task.target, status: "failed", summary: `Error: ${msg}`, rawOutput: "" };
575	    }
576	  });
577	
578	  const settled = await Promise.allSettled(promises);
579	  return settled.map((s, i) =>
580	    s.status === "fulfilled"
581	      ? s.value
582	      : { taskId: tasks[i].taskId, target: tasks[i].target, status: "failed" as const, summary: `Unexpected: ${s.reason}`, rawOutput: "" },
583	  );
584	}
